FROM (VALUES
  ('quadruped-scapular-push-up-hold', 'Quadruped floor push-away hold only.', 'No default sex-based adjustment. Scale by shoulder/wrist tolerance, control quality, and supervision needs rather than gender alone.'),
  ('prone-y-t-w-isometric-series', 'One shape at a time, very low lift.', 'No default sex-based adjustment. Scale by shoulder/wrist tolerance, control quality, and supervision needs rather than gender alone.'),
  ('tall-plank-shoulder-tap', 'Incline plank shoulder tap.', 'No default sex-based adjustment. Scale by shoulder/wrist tolerance, control quality, and supervision needs rather than gender alone.'),
  ('slow-bear-crawl', 'Bear plank hold or hands/knees crawl.', 'No default sex-based adjustment. Scale by shoulder/wrist tolerance, control quality, and supervision needs rather than gender alone.'),
  ('crab-reverse-tabletop-hold', 'Seated rear support with hips low.', 'No default sex-based adjustment. Scale by shoulder/wrist tolerance, control quality, and supervision needs rather than gender alone.'),
  ('wall-handstand-line-hold', 'Wall body-line drill, incline pike hold, or box handstand shape.', 'No default sex-based adjustment. Scale by shoulder/wrist tolerance, control quality, and supervision needs rather than gender alone.'),
  ('wall-handstand-shoulder-shrug', 'Quadruped scapular push-up or pike shoulder shrug.', 'No default sex-based adjustment. Scale by shoulder/wrist tolerance, control quality, and supervision needs rather than gender alone.'),
  ('wall-walk-negative-controlled-wall-walk-down', 'Incline plank walkout or partial wall walk only.', 'No default sex-based adjustment. Scale by shoulder/wrist tolerance, control quality, and supervision needs rather than gender alone.'),
  ('ring-support-hold-assisted-control', 'Parallel-bar support or box-assisted ring support, 3–5 seconds.', 'No default sex-based adjustment. Scale by shoulder/wrist tolerance, control quality, and supervision needs rather than gender alone.'),
  ('wrist-lean-isometric-wrist-support-rock-hold', 'Wrist circles and light quadruped lean.', 'No default sex-based adjustment. Scale by shoulder/wrist tolerance, control quality, and supervision needs rather than gender alone.')
) AS v(slug, guidance, gender_notes)
