INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops position ownership, alignment, and low-speed joint resilience for safer Output and Capacity.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('quadruped-scapular-push-up-hold', 'The scapular push-up or push-up-plus pattern trains scapular protraction and retraction while the elbows stay straight — building serratus and scapular control before higher hand-support demand.', 'Belongs in scapular_quadruped_control (541) — first scapular hand-support control slot before plank taps, crawling, and inversion.', 'Use early in Control / Resilience upper-support blocks, after wrist prep and before tall plank shoulder taps, bear crawls, or wall handstand progressions.', 'Hand-support resilience is precision work — own scapular position, straight arms, and quiet trunk under low load. Not Capacity pressing, Skill shape learning, or Fitness crawl circuits with short rest.', 'Regress support height, assistance, or range before reducing alignment standard; hypermobility athletes need active floor press and should avoid hanging into passive elbow or shoulder end range.'),
  ('prone-y-t-w-isometric-series', 'The prone Y-T-W family trains scapular stabilization and posterior shoulder control with the trunk braced — building lower and mid trap engagement before overhead hand-support work.', 'Belongs in scapular_posterior_chain_control (542) — posterior scapular and shoulder control after quadruped scapular awareness.', 'Use after quadruped scapular push-up hold and before overhead handstand, pressing, or high-volume hand-support blocks.', 'Hand-support resilience is precision work — own scapular position, straight arms, and quiet trunk under low load. Not Capacity pressing, Skill shape learning, or Fitness crawl circuits with short rest.', 'Regress to one shape or wall/band variation before reducing hold quality; hypermobility athletes need active control — avoid end-range hanging.'),
  ('tall-plank-shoulder-tap', 'Shoulder-tap planks challenge trunk and pelvis stability while one hand leaves the ground — training anti-rotation and shoulder support before higher hand-support demand.', 'Belongs in plank_shoulder_control (543) — dynamic shoulder support and anti-rotation after quadruped scapular control.', 'Use after quadruped scapular push-up hold and bear plank shoulder taps, before slow bear crawl or inversion progressions.', 'Hand-support resilience is precision work — own scapular position, straight arms, and quiet trunk under low load. Not Capacity pressing, Skill shape learning, or Fitness crawl circuits with short rest.', 'Regress to incline or bear plank taps before accepting hip rotation; hypermobility athletes need active floor press — avoid collapsing into elbows or wrists.'),
  ('slow-bear-crawl', 'The bear crawl challenges the shoulders to stabilize the upper body while the trunk resists rotation during contralateral movement — building cross-body hand-support control.', 'Belongs in crawling_control (544) — slow contralateral crawling after plank shoulder control.', 'Use after bear plank hold and shoulder taps, before faster crawling, ninja floor transitions, or inversion work.', 'Hand-support resilience is precision work — own scapular position, straight arms, and quiet trunk under low load. Not Capacity pressing, Skill shape learning, or Fitness crawl circuits with short rest.', 'Regress support height, assistance, or range before reducing alignment standard; hypermobility athletes need active floor press and should avoid hanging into passive elbow or shoulder end range.'),
  ('crab-reverse-tabletop-hold', 'Reverse tabletop trains posterior support through the hands while challenging shoulder extension, wrist tolerance, glute engagement, and trunk control — the rear-support counterpart to front plank work.', 'Belongs in posterior_support_control (545) — rear hand-support tolerance after front-support and crawling control.', 'Use after front support and bear work, before reverse crawling, ground transitions, or higher shoulder-extension demand.', 'Hand-support resilience is precision work — own scapular position, straight arms, and quiet trunk under low load. Not Capacity pressing, Skill shape learning, or Fitness crawl circuits with short rest.', 'Regress support height, assistance, or range before reducing alignment standard; hypermobility athletes need active floor press and should avoid hanging into passive elbow or shoulder end range.'),
  ('wall-handstand-line-hold', 'Wall-facing handstand holds teach active shoulder elevation, straight arms, core bracing, and a stacked line — building inverted hand-support control before freestanding or tumbling hand support.', 'Belongs in handstand_line_control (546) — inverted line ownership after crawling and posterior support control.', 'Use after quadruped scapular control, wrist prep, and front support; before wall shrugs, wall walks, or tumbling hand-support skill.', 'Hand-support resilience is precision work — own scapular position, straight arms, and quiet trunk under low load. Not Capacity pressing, Skill shape learning, or Fitness crawl circuits with short rest.', 'Regress support height, assistance, or range before reducing alignment standard; hypermobility athletes need active floor press and should avoid hanging into passive elbow or shoulder end range.'),
  ('wall-handstand-shoulder-shrug', 'Handstand shoulder shrugs train scapular elevation and depression in an inverted support position — strengthening overhead scapular control needed for balance and tumbling hand support.', 'Belongs in overhead_scapular_control (547) — inverted scapular elevation/depression after wall handstand line hold.', 'Use after wall handstand line hold and before wall walk negatives, handstand push-up progressions, or tumbling hand-support skill.', 'Hand-support resilience is precision work — own scapular position, straight arms, and quiet trunk under low load. Not Capacity pressing, Skill shape learning, or Fitness crawl circuits with short rest.', 'Regress support height, assistance, or range before reducing alignment standard; hypermobility athletes need active floor press and should avoid hanging into passive elbow or shoulder end range.'),
  ('wall-walk-negative-controlled-wall-walk-down', 'Controlled wall walks train eccentric shoulder and wrist loading through inversion — building safe handstand exit skill and shoulder endurance before tumbling or advanced handstand work.', 'Belongs in handstand_eccentric_control (548) — controlled inversion descent after wall handstand line hold.', 'Use after wall handstand line hold; pair with line holds and wrist prep before tumbling hand-support skill blocks.', 'Hand-support resilience is precision work — own scapular position, straight arms, and quiet trunk under low load. Not Capacity pressing, Skill shape learning, or Fitness crawl circuits with short rest.', 'Regress support height, assistance, or range before reducing alignment standard; hypermobility athletes need active floor press and should avoid hanging into passive elbow or shoulder end range.'),
  ('ring-support-hold-assisted-control', 'Assisted ring support holds teach straight-arm support and shoulder depression under unstable conditions — building control before ring dips, muscle-ups, or advanced ring skills.', 'Belongs in straight_arm_support_control (549) — assisted ring/bar support after floor and inversion hand-support control.', 'Use after quadruped scapular control and front support; before unassisted ring support, dips, or ring skill work.', 'Hand-support resilience is precision work — own scapular position, straight arms, and quiet trunk under low load. Not Capacity pressing, Skill shape learning, or Fitness crawl circuits with short rest.', 'Regress support height, assistance, or range before reducing alignment standard; hypermobility athletes need active floor press and should avoid hanging into passive elbow or shoulder end range.'),
  ('wrist-lean-isometric-wrist-support-rock-hold', 'Progressive wrist-extension loading under bodyweight builds tissue tolerance for handstands, tumbling, crawling, and ring support without suddenly loading painful ranges.', 'Belongs in wrist_support_control (550) — default wrist-support resilience card before high-volume hand-support work.', 'Use before handstands, bear crawls, ring support, or tumbling hand-support blocks; can be frequent at low intensity.', 'Hand-support resilience is precision work — own scapular position, straight arms, and quiet trunk under low load. Not Capacity pressing, Skill shape learning, or Fitness crawl circuits with short rest.', 'Regress support height, assistance, or range before reducing alignment standard; hypermobility athletes need active floor press and should avoid hanging into passive elbow or shoulder end range.')
) AS v(slug, why_works, why_here, best_placement, misuse, scale_guidance)
